import React from 'react';
import { View } from '../types';
import { ShoppingCartIcon, SearchIcon } from './Icons';

interface HeaderProps {
    cartItemCount: number;
    isAdminView: boolean;
    setView: (view: View) => void;
    setIsAdminView: (isAdmin: boolean) => void;
    searchQuery: string;
    setSearchQuery: (query: string) => void;
}

export const Header: React.FC<HeaderProps> = ({ cartItemCount, isAdminView, setView, setIsAdminView, searchQuery, setSearchQuery }) => {
    const handleNavigation = (view: View) => {
        setIsAdminView(false);
        setView(view);
    }

    const toggleAdminView = () => {
        if (!isAdminView) {
            setIsAdminView(true);
            setView(View.Admin);
        } else {
            setIsAdminView(false);
            setView(View.Home);
        }
    };

    return (
        <header className="bg-white shadow-md sticky top-0 z-50">
            <div className="container mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex items-center justify-between h-20 gap-4">
                    <div className="flex items-center shrink-0 space-x-2 sm:space-x-4">
                        <h1 onClick={() => handleNavigation(View.Home)} className="text-2xl sm:text-3xl font-bold text-primary cursor-pointer">
                            TazaMart
                        </h1>
                        <span className="text-2xl hidden sm:inline">🥦</span>
                    </div>

                    <div className="flex-1 max-w-lg mx-2 sm:mx-4">
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <SearchIcon className="h-5 w-5 text-gray-400" />
                            </div>
                            <input
                                type="text"
                                className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-full leading-5 bg-gray-50 placeholder-gray-500 focus:outline-none focus:bg-white focus:ring-1 focus:ring-primary focus:border-primary sm:text-sm transition duration-150 ease-in-out"
                                placeholder="Search products..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>
                    </div>

                    <nav className="hidden md:flex items-center space-x-6 shrink-0">
                        <a onClick={() => handleNavigation(View.Home)} className="text-gray-600 hover:text-primary transition cursor-pointer">Home</a>
                        <a onClick={() => handleNavigation(View.OrderHistory)} className="text-gray-600 hover:text-primary transition cursor-pointer">My Orders</a>
                        <a onClick={toggleAdminView} className="text-gray-600 hover:text-primary transition cursor-pointer font-semibold">{isAdminView ? 'Exit Admin' : 'Admin Panel'}</a>
                    </nav>

                    <div className="flex items-center shrink-0">
                        <button onClick={() => setView(View.Cart)} className="relative text-gray-600 hover:text-primary transition-colors focus:outline-none">
                            <ShoppingCartIcon className="h-7 w-7" />
                            {cartItemCount > 0 && (
                                <span className="absolute -top-2 -right-2 bg-secondary text-white text-xs rounded-full h-5 w-5 flex items-center justify-center">
                                    {cartItemCount}
                                </span>
                            )}
                        </button>
                    </div>
                </div>
            </div>
        </header>
    );
};

import React from 'react';
import { Product, ProductCategory } from '../types';
import { ProductCard } from './ProductCard';

interface HomeViewProps {
    products: Product[];
    onAddToCart: (product: Product) => void;
    searchQuery: string;
}

export const HomeView: React.FC<HomeViewProps> = ({ products, onAddToCart, searchQuery }) => {
    const categories = Object.values(ProductCategory);

    // Filter products based on search query
    const filteredProducts = products.filter(product => 
        product.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-8">
            <div className="text-center mb-12">
                <h2 className="text-4xl font-extrabold text-dark tracking-tight">Fresh From The Farm</h2>
                <p className="mt-4 text-lg text-gray-500">The best quality fruits and vegetables, delivered to your doorstep.</p>
            </div>

            {filteredProducts.length === 0 ? (
                <div className="text-center py-12">
                    <p className="text-xl text-gray-500">No products found matching "{searchQuery}"</p>
                    <p className="mt-2 text-gray-400">Try checking your spelling or use different keywords.</p>
                </div>
            ) : (
                categories.map(category => {
                    const categoryProducts = filteredProducts.filter(p => p.category === category);
                    if (categoryProducts.length === 0) return null;

                    return (
                        <div key={category} className="mb-12">
                            <h3 className="text-2xl font-bold text-dark border-b-2 border-primary pb-2 mb-6">{category}</h3>
                            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 sm:gap-8">
                                {categoryProducts.map(product => (
                                    <ProductCard key={product.id} product={product} onAddToCart={onAddToCart} />
                                ))}
                            </div>
                        </div>
                    );
                })
            )}
        </div>
    );
};

import React, { useState, useReducer, useCallback } from 'react';
import { Header } from './components/Header';
import { HomeView } from './components/HomeView';
import { CartView } from './components/CartView';
import { CheckoutView } from './components/CheckoutView';
import { OrderConfirmationView } from './components/OrderConfirmationView';
import { OrderHistoryView } from './components/OrderHistoryView';
import { AdminView } from './components/AdminView';
import { Product, CartItem, Order, OrderStatus, View } from './types';
import { initialProducts } from './data';

type AppState = {
    products: Product[];
    cart: CartItem[];
    orders: Order[];
};

type Action =
    | { type: 'ADD_TO_CART'; payload: Product }
    | { type: 'REMOVE_FROM_CART'; payload: number }
    | { type: 'UPDATE_QUANTITY'; payload: { productId: number; quantity: number } }
    | { type: 'PLACE_ORDER'; payload: Order }
    | { type: 'CLEAR_CART' }
    | { type: 'UPDATE_ORDER_STATUS'; payload: { orderId: string; status: OrderStatus } }
    | { type: 'ADD_PRODUCT'; payload: Product }
    | { type: 'UPDATE_PRODUCT'; payload: Product }
    | { type: 'DELETE_PRODUCT'; payload: number };


const appReducer = (state: AppState, action: Action): AppState => {
    switch (action.type) {
        case 'ADD_TO_CART': {
            const existingItem = state.cart.find(item => item.id === action.payload.id);
            if (existingItem) {
                return {
                    ...state,
                    cart: state.cart.map(item =>
                        item.id === action.payload.id ? { ...item, quantity: item.quantity + 1 } : item
                    ),
                };
            }
            return { ...state, cart: [...state.cart, { ...action.payload, quantity: 1 }] };
        }
        case 'REMOVE_FROM_CART':
            return { ...state, cart: state.cart.filter(item => item.id !== action.payload) };
        case 'UPDATE_QUANTITY': {
            if (action.payload.quantity <= 0) {
                 return { ...state, cart: state.cart.filter(item => item.id !== action.payload.productId) };
            }
            return {
                ...state,
                cart: state.cart.map(item =>
                    item.id === action.payload.productId ? { ...item, quantity: action.payload.quantity } : item
                ),
            };
        }
        case 'PLACE_ORDER':
            return { ...state, orders: [...state.orders, action.payload] };
        case 'CLEAR_CART':
            return { ...state, cart: [] };
        case 'UPDATE_ORDER_STATUS':
            return {
                ...state,
                orders: state.orders.map(order =>
                    order.id === action.payload.orderId ? { ...order, status: action.payload.status } : order
                ),
            };
        case 'ADD_PRODUCT':
             return { ...state, products: [...state.products, action.payload] };
        case 'UPDATE_PRODUCT':
            return {
                ...state,
                products: state.products.map(p => (p.id === action.payload.id ? action.payload : p)),
            };
        case 'DELETE_PRODUCT':
            return {
                ...state,
                products: state.products.filter(p => p.id !== action.payload),
            };
        default:
            return state;
    }
};


const App: React.FC = () => {
    const [state, dispatch] = useReducer(appReducer, {
        products: initialProducts,
        cart: [],
        orders: [],
    });

    const [view, setView] = useState<View>(View.Home);
    const [isAdminView, setIsAdminView] = useState(false);
    const [lastOrder, setLastOrder] = useState<Order | null>(null);
    const [searchQuery, setSearchQuery] = useState('');

    const cartItemCount = state.cart.reduce((count, item) => count + item.quantity, 0);

    const onAddToCart = (product: Product) => dispatch({ type: 'ADD_TO_CART', payload: product });
    const onRemoveFromCart = (productId: number) => dispatch({ type: 'REMOVE_FROM_CART', payload: productId });
    const onUpdateQuantity = (productId: number, quantity: number) => dispatch({ type: 'UPDATE_QUANTITY', payload: { productId, quantity } });

    const onPlaceOrder = (order: Order) => {
        dispatch({ type: 'PLACE_ORDER', payload: order });
        setLastOrder(order);
        dispatch({ type: 'CLEAR_CART' });
    };

    const onUpdateOrderStatus = (orderId: string, status: OrderStatus) => dispatch({ type: 'UPDATE_ORDER_STATUS', payload: { orderId, status } });
    const onAddProduct = (product: Product) => dispatch({ type: 'ADD_PRODUCT', payload: product });
    const onUpdateProduct = (product: Product) => dispatch({ type: 'UPDATE_PRODUCT', payload: product });
    const onDeleteProduct = (productId: number) => dispatch({ type: 'DELETE_PRODUCT', payload: productId });

    const renderView = () => {
        switch (view) {
            case View.Home:
                return <HomeView products={state.products} onAddToCart={onAddToCart} searchQuery={searchQuery} />;
            case View.Cart:
                return <CartView cart={state.cart} updateQuantity={onUpdateQuantity} removeFromCart={onRemoveFromCart} setView={setView} />;
            case View.Checkout:
                return <CheckoutView cart={state.cart} placeOrder={onPlaceOrder} setView={setView} />;
            case View.Confirmation:
                return <OrderConfirmationView lastOrder={lastOrder} setView={setView} />;
            case View.OrderHistory:
                return <OrderHistoryView orders={state.orders} />;
            case View.Admin:
                return <AdminView 
                            orders={state.orders} 
                            products={state.products} 
                            updateOrderStatus={onUpdateOrderStatus} 
                            addProduct={onAddProduct}
                            updateProduct={onUpdateProduct}
                            deleteProduct={onDeleteProduct}
                        />;
            default:
                return <HomeView products={state.products} onAddToCart={onAddToCart} searchQuery={searchQuery} />;
        }
    };

    return (
        <div className="flex flex-col min-h-screen">
            <Header 
                cartItemCount={cartItemCount} 
                isAdminView={isAdminView} 
                setView={setView} 
                setIsAdminView={setIsAdminView} 
                searchQuery={searchQuery}
                setSearchQuery={setSearchQuery}
            />
            <main className="flex-grow">
                {renderView()}
            </main>
            <footer className="bg-dark text-white text-center p-4">
                <p>&copy; {new Date().getFullYear()} TazaMart. All rights reserved.</p>
            </footer>
        </div>
    );
};

export default App;

