    const [quantity, setQuantity] = useState(1);

    const handleAddToCart = () => {
        // We add the item 'quantity' times
        for (let i = 0; i < quantity; i++) {
            onAddToCart(product);
        }
        onBack(); // Go back to home or stay? Usually stay or show notification, but for simplicity let's go back or just give feedback. 
        // Requirement said "show detail page... and add admin panel". 
        // I'll just add to cart and user can choose to navigate away.
        // Actually, let's just add to cart.
    };

    return (
        <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-8">
            <button 
                onClick={onBack}
                className="mb-6 flex items-center text-gray-600 hover:text-primary transition-colors"
