                            <input type="text" name="name" value={customer.name} onChange={handleInputChange} className="w-full px-5 py-3 rounded-xl bg-gray-50 border border-gray-100 focus:ring-2 focus:ring-primary/20 outline-none transition" required placeholder="Enter your name" />
                        </div>
                        <div className="md:col-span-2">
