                            </div>
                        </form>
                    </div>
                </div>
            )}

            {selectedOrder && <Invoice order={selectedOrder} onClose={() => setSelectedOrder(null)} />}
        </div>
    );
};

import React, { useState, ChangeEvent } from 'react';
import { CartItem, Customer, Order, View, OrderStatus } from '../types';

interface CheckoutViewProps {
    cart: CartItem[];
    placeOrder: (order: Order) => void;
    setView: (view: View) => void;
}

export const CheckoutView: React.FC<CheckoutViewProps> = ({ cart, placeOrder, setView }) => {
    const [customer, setCustomer] = useState<Customer>({ name: '', address: '', phone: '' });
    const [paymentMethod, setPaymentMethod] = useState<'Easypaisa' | 'JazzCash'>('Easypaisa');
    const [paymentProof, setPaymentProof] = useState<string | null>(null);
    const [paymentProofPreview, setPaymentProofPreview] = useState<string | null>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);

    const total = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

    const handleInputChange = (e: ChangeEvent<HTMLInputElement>) => {
        setCustomer({ ...customer, [e.target.name]: e.target.value });
    };

    const handleFileChange = (e: ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            // Validate file size (e.g., max 5MB for LocalStorage limits)
            if (file.size > 5 * 1024 * 1024) {
                alert("File is too large. Please upload an image under 5MB.");
                return;
            }
            const reader = new FileReader();
            reader.onloadend = () => {
                const base64String = reader.result as string;
                setPaymentProof(base64String);
                setPaymentProofPreview(URL.createObjectURL(file));
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!customer.name || !customer.address || !customer.phone || !paymentProof) {
            alert('Please fill all fields and upload payment proof.');
            return;
        }

        setIsSubmitting(true);
        try {
            const newOrder: Order = {
                id: `TM-${Date.now()}`,
                customer,
                items: cart,
                total,
                status: OrderStatus.Pending,
                paymentMethod,
                paymentProof,
                orderDate: new Date(),
            };
            placeOrder(newOrder);
            setView(View.Confirmation);
        } catch (error) {
            console.error("Order submission failed:", error);
            alert("Storage error: The payment proof image might be too large for local storage. Try a smaller screenshot.");
        } finally {
            setIsSubmitting(false);
        }
    };

    if (cart.length === 0) {
         setView(View.Home);
         return null;
    }

    return (
        <div className="container mx-auto px-4 py-12 pb-32 max-w-6xl">
            <div className="mb-10">
                <h2 className="text-4xl font-black text-dark tracking-tight">Final Step</h2>
                <p className="text-gray-400 mt-2 font-medium">Verify details and complete payment</p>
            </div>

            <form onSubmit={handleSubmit} className="flex flex-col lg:flex-row gap-12">
                <div className="flex-grow space-y-8 animate-in slide-in-from-left-4 duration-500">
                    <div className="bg-white p-10 rounded-[2.5rem] shadow-premium border border-gray-100">
                        <h3 className="text-xl font-black text-dark mb-8 flex items-center">
                            <span className="w-10 h-10 bg-primary/10 text-primary rounded-2xl flex items-center justify-center mr-4 text-sm font-black">01</span>
                            Delivery Details
                        </h3>
                        <div className="space-y-6">
                            <div>
                                <label className="block text-[10px] font-black uppercase text-gray-400 mb-3 tracking-widest">Full Name</label>
                                <input type="text" name="name" value={customer.name} onChange={handleInputChange} className="w-full px-6 py-4 rounded-2xl bg-gray-50 border border-transparent focus:bg-white focus:border-primary/20 focus:ring-4 focus:ring-primary/5 outline-none transition-all font-bold" required placeholder="Who is receiving this order?" />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black uppercase text-gray-400 mb-3 tracking-widest">Phone Number</label>
                                <input type="tel" name="phone" value={customer.phone} onChange={handleInputChange} className="w-full px-6 py-4 rounded-2xl bg-gray-50 border border-transparent focus:bg-white focus:border-primary/20 focus:ring-4 focus:ring-primary/5 outline-none transition-all font-bold" required placeholder="03xx-xxxxxxx" />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black uppercase text-gray-400 mb-3 tracking-widest">Shipping Address</label>
                                <input type="text" name="address" value={customer.address} onChange={handleInputChange} className="w-full px-6 py-4 rounded-2xl bg-gray-50 border border-transparent focus:bg-white focus:border-primary/20 focus:ring-4 focus:ring-primary/5 outline-none transition-all font-bold" required placeholder="House #, Street, Block, Area" />
                            </div>
                        </div>
                    </div>

                    <div className="bg-white p-10 rounded-[2.5rem] shadow-premium border border-gray-100">
                        <h3 className="text-xl font-black text-dark mb-8 flex items-center">
                            <span className="w-10 h-10 bg-primary/10 text-primary rounded-2xl flex items-center justify-center mr-4 text-sm font-black">02</span>
                            Payment Information
                        </h3>

                        <div className="grid grid-cols-2 gap-4 mb-8">
                            <button type="button" onClick={() => setPaymentMethod('Easypaisa')} className={`py-5 rounded-2xl font-black uppercase text-xs tracking-widest transition-all transform active:scale-95 border-2 ${paymentMethod === 'Easypaisa' ? 'bg-primary text-white border-primary shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-primary/20'}`}>Easypaisa</button>
                            <button type="button" onClick={() => setPaymentMethod('JazzCash')} className={`py-5 rounded-2xl font-black uppercase text-xs tracking-widest transition-all transform active:scale-95 border-2 ${paymentMethod === 'JazzCash' ? 'bg-[#da291c] text-white border-[#da291c] shadow-lg' : 'bg-white text-gray-400 border-gray-100 hover:border-primary/20'}`}>JazzCash</button>
                        </div>

                        <div className="p-10 rounded-[2rem] bg-gray-50 text-center mb-8 border border-gray-100">
                            <p className="font-bold text-gray-400 text-sm mb-4 uppercase tracking-widest">Transfer Amount</p>
                            <p className="text-4xl font-black text-dark mb-8">Rs. {total.toLocaleString()}</p>

                            <div className="bg-white p-6 rounded-3xl shadow-soft inline-block mb-6 border border-gray-100">
                                 <img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${paymentMethod}-TazaMart-03001234567`} alt="QR" className="w-32 h-32"/>
                            </div>

                            <div className="space-y-1">
                                <p className="text-2xl font-black text-primary">0300-1234567</p>
                                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Title: Muhammad Alex (TazaMart)</p>
                            </div>
                        </div>

                        <div className="space-y-4">
                            <label className="block text-[10px] font-black uppercase text-gray-400 mb-3 tracking-widest text-center">Upload Screenshot Proof</label>
                            <div className="relative">
                                <input type="file" onChange={handleFileChange} accept="image/*" className="hidden" id="file-upload" required />
                                <label htmlFor="file-upload" className="flex items-center justify-center w-full px-8 py-16 border-2 border-dashed border-primary/20 rounded-[2rem] bg-primary/5 cursor-pointer hover:bg-primary/10 transition-all group overflow-hidden">
                                    {paymentProofPreview ? (
                                        <div className="relative animate-in zoom-in duration-300">
                                            <img src={paymentProofPreview} className="h-48 rounded-2xl shadow-premium object-cover" />
                                            <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity rounded-2xl">
                                                <span className="text-white font-black text-xs uppercase tracking-widest">Replace Proof</span>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="text-center transition-transform group-hover:scale-110">
                                            <div className="text-5xl mb-4">📷</div>
                                            <p className="text-xs font-black text-primary uppercase tracking-widest">Tap to upload proof</p>
                                            <p className="text-[9px] text-gray-400 mt-2 font-bold uppercase tracking-tight">Max Size: 5MB</p>
                                        </div>
                                    )}
                                </label>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="lg:w-[400px] shrink-0 animate-in slide-in-from-right-4 duration-500">
                    <div className="bg-white p-10 rounded-[2.5rem] shadow-premium border border-gray-100 sticky top-28">
                        <h3 className="text-xl font-black text-dark border-b border-gray-50 pb-6 mb-6">Basket Preview</h3>
                        <div className="space-y-4 max-h-[300px] overflow-y-auto pr-4 no-scrollbar">
                            {cart.map(item => (
                                <div key={item.id} className="flex justify-between items-center group">
