                                        </div>
                                    </div>
                                    <span className="font-black text-dark text-xs">Rs. {(item.price * item.quantity).toLocaleString()}</span>
                                </div>
                            ))}
                        </div>
                        <div className="mt-10 pt-8 border-t border-gray-50 space-y-4">
                            <div className="flex justify-between items-center">
                                <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Subtotal</span>
                                <span className="font-bold text-dark text-sm">Rs. {total.toLocaleString()}</span>
