function getOrCreateSheet() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(SHEET_NAME);
  if (!sheet) {
    sheet = ss.insertSheet(SHEET_NAME);
    sheet.appendRow(["id", "name", "price", "image", "category", "unit", "description"]);
  }
  return sheet;
}

function doGet() {
  try {
    const sheet = getOrCreateSheet();
    const data = sheet.getDataRange().getValues();
    if (data.length <= 1) return createJsonResponse([]);

    const headers = data.shift();
    const products = data.map(row => {
      const obj = {};
      headers.forEach((header, i) => {
        obj[header] = row[i];
      });
      return obj;
    });

    return createJsonResponse(products);
  } catch (error) {
    return createJsonResponse({ error: error.toString() });
  }
}

function doPost(e) {
  try {
    const jsonString = e.postData.contents;
    const params = JSON.parse(jsonString);
    const sheet = getOrCreateSheet();
    const data = sheet.getDataRange().getValues();

    if (params.action === 'add' || params.action === 'edit') {
      const p = params.product;
      const rowData = [p.id, p.name, p.price, p.image, p.category, p.unit, p.description];

      let foundIndex = -1;
      for (let i = 1; i < data.length; i++) {
        if (data[i][0] == p.id) {
          foundIndex = i + 1;
          break;
        }
      }

      if (foundIndex > -1) {
        sheet.getRange(foundIndex, 1, 1, rowData.length).setValues([rowData]);
      } else {
        sheet.appendRow(rowData);
      }
    } else if (params.action === 'delete') {
      for (let i = 1; i < data.length; i++) {
        for (let i = 1; i < data.length; i++) {
          if (data[i][0] == params.id) {
            sheet.deleteRow(i + 1);
            break;
          }
        }
      }
    }

    return createJsonResponse({ status: 'success' });
  } catch (error) {
    return createJsonResponse({ status: 'error', error: error.toString() });
  }
}

function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}
