I will update the application to handle both **Products** and **Orders** synchronization with your Google Sheets backend. This requires updating the Google Apps Script to manage two sheets and modifying the frontend to fetch and push order data.

### 1. Updated Google Apps Script (Required)
Please replace your existing Google Apps Script with this version. It automatically creates both "Products" and "Orders" sheets and handles the complex data structures (like cart items) by storing them as JSON strings.

```javascript
/**
 * TazaMart Full Backend Script (Products & Orders)
 */

const PRODUCT_SHEET = "Products";
const ORDER_SHEET = "Orders";

function getSheet(name) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  let sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    if (name === PRODUCT_SHEET) {
      sheet.appendRow(["id", "name", "price", "image", "category", "unit", "description"]);
    } else if (name === ORDER_SHEET) {
      sheet.appendRow(["orderId", "orderDate", "customerName", "customerPhone", "customerAddress", "total", "status", "paymentMethod", "itemsJson", "paymentProof"]);
    }
  }
  return sheet;
}

function doGet() {
  try {
    const productSheet = getSheet(PRODUCT_SHEET);
    const orderSheet = getSheet(ORDER_SHEET);

    const products = getRowsData(productSheet);
    const rawOrders = getRowsData(orderSheet);

    // Format orders for frontend
    const orders = rawOrders.map(o => ({
      id: o.orderId,
      orderDate: o.orderDate,
      total: parseFloat(o.total),
      status: o.status,
      paymentMethod: o.paymentMethod,
      paymentProof: o.paymentProof,
      customer: {
        name: o.customerName,
        phone: o.customerPhone,
        address: o.customerAddress
      },
      items: JSON.parse(o.itemsJson || '[]')
    }));

    return createResponse({ products, orders });
  } catch (error) {
    return createResponse({ error: error.toString() });
  }
}

function doPost(e) {
  try {
    const params = JSON.parse(e.postData.contents);
    const action = params.action;

    if (action === 'add' || action === 'edit') {
      const p = params.product;
      const sheet = getSheet(PRODUCT_SHEET);
      upsertRow(sheet, p.id, [p.id, p.name, p.price, p.image, p.category, p.unit, p.description]);
    } 
    else if (action === 'delete') {
      const sheet = getSheet(PRODUCT_SHEET);
      deleteRow(sheet, params.id);
    } 
    else if (action === 'addOrder') {
      const o = params.order;
      const sheet = getSheet(ORDER_SHEET);
      sheet.appendRow([
        o.id, 
        o.orderDate, 
        o.customer.name, 
        o.customer.phone, 
        o.customer.address, 
        o.total, 
        o.status, 
        o.paymentMethod, 
        JSON.stringify(o.items), 
        o.paymentProof
      ]);
    }
    else if (action === 'updateOrderStatus') {
      const sheet = getSheet(ORDER_SHEET);
      updateStatus(sheet, params.orderId, params.status);
    }

    return createResponse({ status: 'success' });
  } catch (error) {
    return createResponse({ status: 'error', error: error.toString() });
  }
}

// --- Helpers ---

function createResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON);
}

function getRowsData(sheet) {
  const data = sheet.getDataRange().getValues();
  if (data.length <= 1) return [];
  const headers = data.shift();
  return data.map(row => {
    const obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  });
}

function upsertRow(sheet, id, rowData) {
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == id) {
      sheet.getRange(i + 1, 1, 1, rowData.length).setValues([rowData]);
      return;
    }
  }
  sheet.appendRow(rowData);
}

function deleteRow(sheet, id) {
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == id) {
      sheet.deleteRow(i + 1);
      return;
    }
  }
}

function updateStatus(sheet, orderId, status) {
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == orderId) {
      sheet.getRange(i + 1, 7).setValue(status); // Column 7 is status
      return;
    }
  }
}
```

