    lang: Language;
}

const translations = {
    [Language.EN]: {
        title: "My Basket",
        empty: "Your basket is empty",
        start: "Start Shopping",
        summary: "Order Summary",
        subtotal: "Subtotal",
        delivery: "Delivery",
        free: "FREE",
        total: "Total",
        checkout: "Checkout Now"
